import re

IPV4_PATTERN = re.compile(
    r'^(?:(?:25[0-5]|2[0-4]\d|1\d{2}|[1-9]?\d)\.){3}'
    r'(?:25[0-5]|2[0-4]\d|1\d{2}|[1-9]?\d)$'
)

def is_valid_ipv4(address: str) -> bool:
    """Check if a string is a valid IPv4 address.

    Rejects addresses with octets outside 0-255 range,
    leading zeros, and partial addresses.
    """
    if not address:
        return False
    return bool(IPV4_PATTERN.match(address))

from typing import Any, Dict, List, Tuple

def unflatten(pairs: List[Tuple[str, Any]]) -> Dict[str, Any]:
    """Transform flat dot-separated key-value pairs into a nested dictionary.

    Args:
        pairs: List of (key, value) tuples where keys use dot notation.

    Returns:
        Nested dictionary.

    Examples:
        >>> unflatten([('a.b.c', 1), ('a.b.d', 2), ('x', 3)])
        {'a': {'b': {'c': 1, 'd': 2}}, 'x': 3}
    """
    result: Dict[str, Any] = {}
    for key, value in pairs:
        parts = key.split('.')
        current = result
        for part in parts[:-1]:
            if part not in current:
                current[part] = {}
            current = current[part]
        current[parts[-1]] = value
    return result

