import threading
from typing import Any, Callable, Dict, List, Optional

class MessageBroker:
    """Thread-safe pub/sub message broker with topic-based routing.

    Topics support wildcard patterns:
    - 'sensor.temperature' matches exactly
    - 'sensor.*' matches 'sensor.temperature', 'sensor.humidity'
    - 'sensor.>' matches 'sensor.temperature', 'sensor.room.bedroom.temp'
    """

    def __init__(self) -> None:
        self._subscriptions: Dict[str, List[Callable[[str, Any], None]]] = {}
        self._lock = threading.Lock()

    def subscribe(self, topic: str, handler: Callable[[str, Any], None]) -> None:
        """Subscribe a handler to a topic pattern.

        Args:
            topic: Topic pattern (supports * and > wildcards).
            handler: Callback receiving (topic, payload).
        """
        with self._lock:
            self._subscriptions.setdefault(topic, []).append(handler)

    def unsubscribe(self, topic: str, handler: Callable[[str, Any], None]) -> None:
        """Remove a handler from a topic."""
        with self._lock:
            handlers = self._subscriptions.get(topic, [])
            if handler in handlers:
                handlers.remove(handler)

    def publish(self, topic: str, payload: Any) -> int:
        """Publish a message to all matching topic handlers.

        Returns:
            Number of handlers that received the message.
        """
        count = 0
        with self._lock:
            for pattern, handlers in self._subscriptions.items():
                if self._topic_matches(pattern, topic):
                    for handler in handlers:
                        handler(topic, payload)
                        count += 1
        return count

    @staticmethod
    def _topic_matches(pattern: str, topic: str) -> bool:
        if pattern == topic:
            return True
        parts_pattern = pattern.split('.')
        parts_topic = topic.split('.')
        return MessageBroker._match_parts(parts_pattern, parts_topic)

    @staticmethod
    def _match_parts(pattern_parts: List[str], topic_parts: List[str]) -> bool:
        pi = 0
        ti = 0
        while pi < len(pattern_parts) and ti < len(topic_parts):
            if pattern_parts[pi] == '>':
                return True
            if pattern_parts[pi] == '*' or pattern_parts[pi] == topic_parts[ti]:
                pi += 1
                ti += 1
            else:
                return False
        return pi == len(pattern_parts) and ti == len(topic_parts)
